insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:3-1-economic-growth:mcq:1ac70ddf', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "A country''s GDP growth was +2.7%, −1.4%, +2.3% and +1.8% over four years. In which year did output actually FALL?", "options": ["The year with −1.4%", "Output never rose", "The year with +1.8%", "The year with +2.3%"]}'::jsonb, '{"answer": 0, "explain": "Only a NEGATIVE growth rate means output fell. A smaller positive figure (+1.8%) still means GDP is rising, just more slowly."}'::jsonb),
('economics:3-1-economic-growth:mcq:2fd72ae5', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "Real GDP differs from nominal GDP because real GDP...", "options": ["Excludes services", "Is adjusted for inflation, showing actual output", "Only counts government spending", "Is divided by the population"]}'::jsonb, '{"answer": 1, "explain": "Nominal GDP is in money terms and rises with prices. Real GDP takes inflation out, so it reflects genuine output."}'::jsonb),
('economics:3-1-economic-growth:mcq:4d3dbe58', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "In Year 1 real GDP growth is 5% and nominal GDP growth is 5%. What can you conclude?", "options": ["Real GDP fell", "There was no inflation in Year 1", "The population fell", "Inflation was 10%"]}'::jsonb, '{"answer": 1, "explain": "Nominal growth includes price rises. If nominal and real growth are equal, prices did not rise — no inflation."}'::jsonb),
('economics:3-1-economic-growth:mcq:50b65b3e', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "Which is a determinant of LONG-RUN economic growth?", "options": ["An increase in the quantity or quality of the factors of production", "A rise in the price level", "A short-term rise in consumer spending", "A fall in the exchange rate"]}'::jsonb, '{"answer": 0, "explain": "Long-run growth needs greater productive capacity, which comes from more or better land, labour, capital and enterprise. Short-run growth comes from rising aggregate demand."}'::jsonb),
('economics:3-1-economic-growth:mcq:e49dea03', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "Which is most likely to REDUCE economic growth?", "options": ["An increase in exports", "Low interest rates", "A stable price level", "High taxes on profits"]}'::jsonb, '{"answer": 3, "explain": "High profit taxes leave firms less to reinvest and weaken the incentive to expand. The other three support growth."}'::jsonb),
('economics:3-1-economic-growth:mcq:2ea113bd', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "Which is normally counted as part of a country''s GDP?", "options": ["Household savings", "Investment spending by firms", "Unpaid domestic work within a family", "Interest rates"]}'::jsonb, '{"answer": 1, "explain": "Investment is a component of GDP. Savings are income NOT spent, interest rates are a price, and unpaid domestic work is not recorded."}'::jsonb),
('economics:3-1-economic-growth:mcq:3926eb38', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'mcq', 'mcq', 1, '{"question": "A country''s GDP rises 1.7% but its population rises 2.0%. What happens to GDP per capita?", "options": ["It rises by 1.7%", "It rises by 3.7%", "It falls, because population grew faster than output", "It stays exactly the same"]}'::jsonb, '{"answer": 2, "explain": "GDP per capita = GDP ÷ population. If the population grows faster than output, each person''s share shrinks — so average living standards fall despite positive growth."}'::jsonb),
('economics:3-1-economic-growth:tf:f96352d6', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "A falling but still positive growth rate means the economy is shrinking."}'::jsonb, '{"answer": false, "explain": "It means the economy is still GROWING, just more slowly. Only a negative growth rate means output actually fell — a classic student error."}'::jsonb),
('economics:3-1-economic-growth:tf:928840f1', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "If a country''s GDP growth is positive every year, its level of GDP is highest in the final year."}'::jsonb, '{"answer": true, "explain": "Positive growth every year means GDP rose every year, so the LEVEL is highest at the end. The year with the fastest growth is not the year with the most GDP."}'::jsonb),
('economics:3-1-economic-growth:tf:b7910b2d', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "Real GDP is adjusted for inflation."}'::jsonb, '{"answer": true, "explain": "Real GDP = nominal GDP ÷ the average price level, so it shows actual output rather than just rising prices."}'::jsonb),
('economics:3-1-economic-growth:tf:6fa2cf18', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "GDP per capita tells you how income is distributed within a country."}'::jsonb, '{"answer": false, "explain": "It is only an AVERAGE (GDP ÷ population). It says nothing about distribution — an official OCR misconception. A country can have a high average with severe inequality."}'::jsonb),
('economics:3-1-economic-growth:tf:6d339c5a', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "Economic growth can raise government tax revenue without raising tax rates."}'::jsonb, '{"answer": true, "explain": "More people in work and higher profits mean more income and business tax is collected at the same rates — plus less is spent on unemployment benefits."}'::jsonb),
('economics:3-1-economic-growth:tf:3cb1d5df', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "In economics, ''investment'' means buying shares on the stock market."}'::jsonb, '{"answer": false, "explain": "In economics investment means firms spending on CAPITAL — machinery, premises, technology — which raises future productive capacity."}'::jsonb),
('economics:3-1-economic-growth:tf:e7b146ea', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "GDP per capita can fall even when a country''s GDP is rising."}'::jsonb, '{"answer": true, "explain": "If the population grows faster than output, each person''s share shrinks. This is why the UK''s per capita growth (1.10%) is below its GDP growth (1.67%)."}'::jsonb),
('economics:3-1-economic-growth:tf:ce089437', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tf', 'tf', 1, '{"question": "Economic growth always makes everyone in a country better off."}'::jsonb, '{"answer": false, "explain": "The gains are rarely shared evenly — inequality can widen even as the economy grows. Growth also brings pollution, congestion and resource depletion."}'::jsonb),
('economics:3-1-economic-growth:learn:c5131d14', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'learn', 'mcq', 1, '{"readingTitle": "What economic growth is — GDP, real GDP and GDP per capita", "reading": "<p><strong>Economic growth is the growth over time of GDP</strong> — an increase in the value of the goods and services an economy produces. It is normally given as a percentage change per year.</p>\n<h4>The four terms — learn all four</h4>\n<ul>\n<li><strong>GDP (Gross Domestic Product)</strong> — the total value of goods and services produced in a country in a year. This is <strong>nominal GDP</strong>, measured in money terms.</li>\n<li><strong>Real GDP</strong> — GDP adjusted for inflation, so it shows ACTUAL output rather than just rising prices. Real GDP = nominal GDP ÷ the average price level. This is what growth is properly measured by.</li>\n<li><strong>GDP per capita</strong> — GDP ÷ population. The output (and roughly the income) of the average person, so it is the better guide to living standards.</li>\n<li><strong>Negative growth</strong> — when output actually falls. A <strong>recession</strong> is commonly two consecutive quarters of negative growth.</li>\n</ul>\n<h4>Short-run vs long-run growth</h4>\n<ul>\n<li><strong>Short-run growth</strong> — the actual annual percentage change in real national output.</li>\n<li><strong>Long-run growth</strong> — an increase in the economy''s <strong>potential productive capacity</strong>. This is the definition the exam wants for \"the best definition of economic growth\".</li>\n</ul>\n<h4>Why GDP per capita matters</h4>\n<ul>\n<li>A country can have a large total GDP but a low GDP per capita if its population is huge — China''s total GDP dwarfs the UK''s, but the UK''s GDP per capita is higher.</li>\n<li>If population grows FASTER than output, GDP per capita can fall even while GDP rises. This is exactly why the UK''s per capita growth (1.10%) is below its GDP growth (1.67%) — its population grows about 0.6% a year.</li>\n</ul>\n<p><strong>What UK GDP is made of:</strong> services are roughly <strong>80%</strong> of it — retail, financial services, tourism, education and the creative arts — plus exports such as high-tech aerospace, and smaller older industries like agriculture and mining.</p>", "question": "Why is real GDP a better measure of growth than nominal GDP?", "options": ["It only counts exports", "It measures the government''s budget", "It strips out inflation, so it shows actual output not just higher prices", "It divides output by the population"]}'::jsonb, '{"answer": 2, "explain": "Nominal GDP rises when prices rise even if nothing extra is made. Real GDP adjusts for inflation, showing genuine output. Dividing by population gives GDP per capita — a different measure."}'::jsonb),
('economics:3-1-economic-growth:learn:fedd9ac6', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'learn', 'mcq', 1, '{"readingTitle": "Measuring growth — the calculations and reading the data", "reading": "<p>Every 3.1 paper contains calculations and a data question. The maths is simple; the marks are lost through carelessness and through misreading what a chart shows.</p>\n<h4>The formulas</h4>\n<ul>\n<li><strong>Growth rate (%)</strong> = ((GDP this year − GDP last year) ÷ GDP last year) × 100. If GDP was £50bn and is now £55bn, growth = 10%.</li>\n<li><strong>GDP per capita</strong> = GDP ÷ population. £150 billion ÷ 5m = £30,000.</li>\n<li><strong>Real GDP</strong> = nominal GDP ÷ average price level. £10bn with 5% inflation → £9.52bn.</li>\n<li><strong>Applying a growth rate</strong>: £500m growing 4% → £500m × 1.04 = £520m.</li>\n</ul>\n<h4>The single biggest trap: RATE of change vs LEVEL</h4>\n<ul>\n<li>A growth-rate chart shows how FAST GDP is rising, not how BIG it is. <strong>If every year''s growth is positive, GDP is rising every year</strong> — so the level is highest in the LAST year and lowest in the FIRST.</li>\n<li>In the real paper, candidates saw the 3.0% peak in 2014 and wrongly answered \"GDP was highest in 2014\". The correct answers were 2019 (highest) and 2010 (lowest).</li>\n<li>A growth rate that is positive but FALLING (3.0% → 1.65%) means the economy is <strong>still growing, just more slowly</strong>. Saying it \"shrank\" is a classic error. Only a NEGATIVE figure means output actually fell.</li>\n</ul>\n<h4>Describing data: summarise the pattern</h4>\n<ul>\n<li>Too little: \"The trend is upwards.\" Too much: reading out every value. Aim for the overall shape — \"rose steadily to a peak around 2014, then fell away before levelling off\".</li>\n<li><strong>Never just re-write the data.</strong> Saying one figure is higher than another is the START of a chain of reasoning, not the analysis itself — you must explain WHY.</li>\n</ul>", "question": "A country''s GDP growth is +3.0% in 2014 and +1.65% in 2018. What happened to the LEVEL of GDP?", "options": ["It rose in both years, but more slowly in 2018", "It was highest in 2014", "It fell in 2018", "It stayed the same"]}'::jsonb, '{"answer": 0, "explain": "Both figures are positive, so GDP grew both years — just at a slower rate in 2018. GDP is therefore HIGHER in 2018 than 2014. Confusing the rate with the level is the topic''s biggest trap."}'::jsonb),
('economics:3-1-economic-growth:learn:5a9bc0e1', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'learn', 'mcq', 1, '{"readingTitle": "The determinants of economic growth", "reading": "<p>Output is made using the <strong>factors of production</strong>, so growth depends on the <strong>quantity and quality</strong> of those factors. In the short run growth comes from rising <strong>aggregate demand</strong> (consumer spending, investment, government spending or exports); in the long run it needs an increase in <strong>productive capacity</strong>.</p>\n<h4>Investment (capital)</h4>\n<ul>\n<li>In economics, investment means <strong>spending on capital equipment</strong> — premises, tools, machinery — NOT buying shares or saving in a bank.</li>\n<li>Better capital raises future capacity: new premises, automating production, better equipment. Lower interest rates and expectations of growth encourage firms to invest.</li>\n</ul>\n<h4>Changes in technology</h4>\n<ul>\n<li>Technology constantly improves, so newer capital is more efficient and produces more than older equipment — a modern smartphone outguns the 1969 Moon-landing computers.</li>\n</ul>\n<h4>Education and training (human capital)</h4>\n<ul>\n<li>Better-educated, better-trained workers are <strong>more productive</strong>, so each worker is worth more to a firm and total output rises. Training targeted at skills shortages moves the economy forward faster.</li>\n</ul>\n<h4>Size of the workforce</h4>\n<ul>\n<li>A bigger workforce raises potential output. The UK has an ageing population — more dependants supported by a relatively smaller working-age group — and <strong>immigration</strong> can help offset this.</li>\n</ul>\n<h4>Availability of natural resources</h4>\n<ul>\n<li>Exploitable resources aid growth: the UK relied on coal and steel, then North Sea oil (now declining), and increasingly renewable energy.</li>\n</ul>\n<h4>Government policies</h4>\n<ul>\n<li><strong>Fiscal policy</strong> — cut taxes (more disposable income and investment) or raise spending (infrastructure, public services).</li>\n<li><strong>Monetary policy</strong> — lower interest rates make saving less attractive and borrowing cheaper, raising consumption and investment.</li>\n<li><strong>Supply-side policy</strong> — training and education, immigration, infrastructure. Poor <strong>infrastructure</strong> (transport, and now broadband) holds economies back.</li>\n</ul>", "question": "In economics, ''investment'' as a determinant of growth means...", "options": ["Putting money into a savings account", "Firms spending on capital equipment such as machinery and premises", "The government paying benefits", "Households buying shares on the stock market"]}'::jsonb, '{"answer": 1, "explain": "Investment means spending on capital that raises future productive capacity — not buying shares or saving, which is what ''investment'' means in everyday speech."}'::jsonb),
('economics:3-1-economic-growth:learn:cfd4d130', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'learn', 'mcq', 1, '{"readingTitle": "The costs and benefits of economic growth", "reading": "<p>The spec asks you to <strong>evaluate</strong> growth, including its impact on <strong>economic, social and environmental sustainability</strong>. You need both sides and a supported judgement.</p>\n<h4>Benefits</h4>\n<ul>\n<li><strong>Higher living standards</strong> — if output grows faster than population, GDP per capita rises, so there is more to go around and average wages rise.</li>\n<li><strong>Lower unemployment</strong> — producing extra output needs more workers.</li>\n<li><strong>More tax revenue</strong> — firms sell more and more people work, so income and business tax revenue rises WITHOUT raising tax rates, and less is spent on unemployment benefits.</li>\n<li><strong>Better public services</strong> — that revenue funds hospitals and schools, which then FEED BACK into growth: healthier workers take fewer sick days, better-schooled workers are more productive.</li>\n<li><strong>Reduced poverty</strong> — as average incomes rise, though only if the gains are shared.</li>\n</ul>\n<h4>Costs</h4>\n<ul>\n<li><strong>Negative externalities</strong> — pollution of land, sea and air, noise and congestion. London''s Congestion Charge and ULEZ exist to fight vehicle pollution.</li>\n<li><strong>Global warming</strong> — emissions melt ice caps and raise sea levels; the 2016 Paris Accord tried to control this.</li>\n<li><strong>Depletion of non-renewable resources</strong> — mining scars land; palm-oil plantations drive deforestation, cutting the world''s capacity to absorb CO₂.</li>\n<li><strong>Inflation</strong> — if demand grows faster than productive capacity, prices rise instead of output.</li>\n<li><strong>Inequality</strong> — the gains are rarely shared evenly; employers may gain far more than workers, and the unemployed depend on the government redistributing.</li>\n<li><strong>Lower quality of life for some</strong> — urbanisation, congestion, housing pressure, and less family time. \"More stuff\" is not automatically a better life.</li>\n</ul>\n<h4>The three sustainabilities</h4>\n<ul>\n<li><strong>Economic</strong> — can the growth be maintained (or does it cause inflation/debt)? <strong>Social</strong> — does quality of life and fairness improve? <strong>Environmental</strong> — can the planet sustain it?</li>\n<li>A real MCQ: wind farms raise energy prices (economic ↓) and noise (social ↓) but replace fossil fuels (environmental ↑).</li>\n</ul>", "question": "Economic growth raises government tax revenue. Why is that a benefit?", "options": ["It means tax rates must rise", "It automatically ends inequality", "More revenue funds public services like schools and hospitals, which can further raise growth", "It reduces the size of the workforce"]}'::jsonb, '{"answer": 2, "explain": "Growth raises revenue WITHOUT raising rates, and that revenue funds healthcare and education — which make workers more productive and drive further growth. Growth does not automatically end inequality; the gains may be shared unevenly."}'::jsonb),
('economics:3-1-economic-growth:misc:a2aca0c1', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The chart shows growth peaked at 3.0% in 2014, so the UK''s GDP was highest in 2014.\"</p><p><strong>✅ The correct idea:</strong> This is the single biggest trap in 3.1, and the real mark scheme flags it as a Misconception. A growth-rate chart shows how FAST GDP is rising, not how BIG it is. Because every year from 2010 to 2019 had POSITIVE growth, GDP rose every single year — so the LEVEL was highest in 2019 (the last year) and lowest in 2010 (the first). The 3.0% peak in 2014 was just the fastest growth. Candidates who answered ''2014 highest, 2011–12 lowest'' were confusing rates of change with absolute values. Rule: positive rate = still rising; only a NEGATIVE bar means the level actually fell.</p>", "question": "GDP growth is positive every year from 2010 to 2019, peaking at 3.0% in 2014. GDP was highest in...", "options": ["2014", "Cannot be known", "2010", "2019"]}'::jsonb, '{"answer": 3, "explain": "Positive growth every year means GDP rose every year, so the level is highest at the END (2019). 2014 is only the fastest growth."}'::jsonb),
('economics:3-1-economic-growth:misc:ea20c4b6', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"GDP per capita of £32,311 means each UK person has £32,311 — so it shows how income is shared out.\"</p><p><strong>✅ The correct idea:</strong> The official OCR Misconception box on this paper: candidates confuse GDP per capita as an AVERAGE with wealth or income DISTRIBUTION, which is a completely different concept. GDP per capita is simply total GDP ÷ population — a mathematical average. It tells you nothing about who actually receives the income: a country could have a high GDP per capita while most people are poor and a few are extremely rich. (Distribution is measured differently — see 3.3.) The examiners also report candidates wrongly believing GDP per capita is measured per household, per family or per region. It is per PERSON.</p>", "question": "What does GDP per capita NOT tell you?", "options": ["Roughly the typical person''s income", "How income is distributed between rich and poor", "The output of the average person", "How the country compares with others over time"]}'::jsonb, '{"answer": 1, "explain": "It is only an average (GDP ÷ population). Distribution is a separate concept — confusing the two is an official OCR misconception."}'::jsonb),
('economics:3-1-economic-growth:misc:78687645', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Uganda''s GDP per capita is £506.6 and the UK''s is £32,311. That''s my analysis done.\"</p><p><strong>✅ The correct idea:</strong> The Assessment for Learning note on this paper is explicit: candidates must NOT describe or re-write the data. Stating that one figure is higher or lower than another is only the BEGINNING of an analytical chain of reasoning, not the analysis itself. You must explain WHY: Uganda is a less developed economy whose output is largely low-value primary agriculture, while the UK''s comes from high-value manufacturing and services — which is why the gap is roughly sixtyfold. Then go further: Uganda''s growth RATE is higher (5.2% vs 2.3%) partly because it starts from such a low base, but its fast population growth means per capita growth is only about 1% a year. Data + reason + consequence = analysis.</p>", "question": "You''ve noted Uganda''s GDP per capita is far below the UK''s. To turn this into ANALYSIS you must...", "options": ["State which is bigger", "Quote more figures from the table", "Explain WHY — e.g. low-value primary output vs high-value services", "Repeat the numbers in a sentence"]}'::jsonb, '{"answer": 2, "explain": "Re-writing data scores nothing. Comparing figures is the start of a chain; the marks come from explaining the reason and its consequence."}'::jsonb),
('economics:3-1-economic-growth:misc:07358415', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"I''ll list three benefits of globalisation, then three completely different problems at the end.\"</p><p><strong>✅ The correct idea:</strong> The examiners were blunt about this on the Tanzania question. Evaluation is not a list of unconnected good and bad points, and it is not a conclusion that just summarises. A good evaluative point must MATCH the analytical point it answers — it should strengthen, mitigate or contrast with it. So: ''workers gain jobs in multinational factories (analysis) — HOWEVER those same factories out-compete local village producers, so other workers lose their jobs (matching evaluation)''. Exemplar 3 on the real paper made a sensible point about living standards and then evaluated with an unrelated point about structural unemployment — which did not earn the evaluation marks. Pair every point with its own counter.</p>", "question": "What makes a MATCHING evaluative point?", "options": ["It repeats the analysis in different words", "It summarises all previous points", "It raises a completely separate disadvantage", "It strengthens, mitigates or contrasts with the specific point just made"]}'::jsonb, '{"answer": 3, "explain": "Evaluation must answer the point it follows. Unconnected lists and summary conclusions score poorly — the examiners said so explicitly."}'::jsonb),
('economics:3-1-economic-growth:misc:cbc5ca6c', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Growth means more government spending on healthcare, which improves life expectancy.\"</p><p><strong>✅ The correct idea:</strong> The chain is missing its first links, and the examiners penalised exactly this. Starting at ''increased spending on health'' never connects back to ECONOMIC GROWTH, which is what the question asked about. Include every simple link: growth raises output and incomes → higher incomes and profits mean more tax revenue at the same tax rates → the government can spend more on healthcare and education → life expectancy and future earnings rise. Each link is obvious on its own, but leaving the early ones out breaks the chain and caps your marks. The same discipline rescues the ''education → GDP'' chain: more schooling → higher literacy → more productive workers → more output per worker → higher GDP.</p>", "question": "Why must an analysis chain start from economic growth itself?", "options": ["Otherwise the later links don''t connect to the question that was asked", "Because data must be quoted first", "Because you must always define GDP first", "Because examiners want longer answers"]}'::jsonb, '{"answer": 0, "explain": "The examiners noted responses starting at ''increased spending on health'' failed to link back to growth. Include all the simple early links."}'::jsonb),
('economics:3-1-economic-growth:tips:631e8473', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tips', 'mcq', 1, '{"readingTitle": "data — Data questions: rate vs level, and never re-write the data", "reading": "<p>Every 3.1 paper has a chart or table, and two failures come up again and again in the examiner reports:</p>\n<ul>\n<li><strong>Rate ≠ level.</strong> Positive growth every year means the LEVEL rose every year — highest at the end (2019), lowest at the start (2010). The 3.0% peak in 2014 is the fastest growth, not the biggest GDP. Candidates who answered 2014 lost the marks.</li>\n<li><strong>Don''t re-write the data.</strong> \"One figure is higher than another\" is the START of a chain, not the analysis. Add the reason and the consequence.</li>\n<li><strong>Summarise the pattern</strong>: \"rose steadily to a peak around 2014, then fell away and levelled off\" beats listing every value.</li>\n</ul>\n<h4>Cover everything the question names</h4>\n<p>The UK/Japan question required Japan AND the UK, and GDP AND GDP per capita, to reach Level 3. Tick off each named element before you finish.</p>", "question": "A chart shows positive GDP growth every year, peaking in 2014. In which year is the LEVEL of GDP highest?", "options": ["2014", "The first year", "You cannot tell", "The final year"]}'::jsonb, '{"answer": 3, "explain": "Positive growth every year = GDP rising every year, so the level is highest at the end. This exact trap cost candidates marks on the real paper."}'::jsonb),
('economics:3-1-economic-growth:tips:6a646e4b', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tips', 'mcq', 1, '{"readingTitle": "calculation — Calculations: the £ sign, the units, and showing working", "reading": "<p>The maths is easy; the marks go on precision. Real examples from this paper:</p>\n<ul>\n<li><strong>Average</strong>: (539 + 552 + 794) ÷ 3 = $628.33 — use the right years. Some candidates picked data from the wrong rows.</li>\n<li><strong>Applying a growth rate</strong>: £1,797 trillion × 1.015 = £1,823.96 trillion. <strong>Omitting the £ or the word \"trillion\" cost a mark.</strong></li>\n<li><strong>GDP per capita</strong>: £2,055,991.7 million ÷ 65,128,861 = £31,568.1 — watch that GDP is in MILLIONS, and <strong>the £ sign is required for full marks</strong>.</li>\n<li><strong>Show your working</strong> so the Own Figure Rule can rescue a slip — a bare wrong answer scores zero.</li>\n</ul>", "question": "UK GDP in 2011 was £1,797 trillion and 2012 growth was 1.5%. GDP in 2012 was...", "options": ["£26.96 trillion", "£1,823.96 billion", "£1,823.96", "£1,823.96 trillion"]}'::jsonb, '{"answer": 3, "explain": "£1,797 × 1.015 = £1,823.955. The mark scheme gives only 1 mark if the £ sign or the word ''trillion'' is missing."}'::jsonb),
('economics:3-1-economic-growth:tips:6c5252f2', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tips', 'mcq', 1, '{"readingTitle": "analysis — Analyse: build every link in the chain", "reading": "<p>Analyse questions carry no evaluation marks — spend the time on developed chains instead.</p>\n<ul>\n<li><strong>Include all the simple links.</strong> Education → higher literacy → more productive workers → more output per worker → higher GDP. Skipping the early links breaks the chain.</li>\n<li><strong>Two developed chains beat five one-liners.</strong> Correct analysis \"in the form of developed links… through a chain of reasoning\" is what Level 3 asks for.</li>\n<li><strong>Apply it</strong> — you cannot get the AO2 marks without referring to the extract, and on some questions \"if there is no analysis, application cannot be rewarded\".</li>\n</ul>\n<h4>The household-income chain worth memorising</h4>\n<p>Incomes rise → consumers afford more → demand rises → firms raise output (this IS growth) → producing it pays incomes to others → they spend too → more output again (the multiplier). Then add: extra income for the richest 20% has less effect, because they save more of it.</p>", "question": "For a 6-mark ''Analyse'' question, what earns the top level?", "options": ["Quoting as much data as possible", "Developed links forming a chain of reasoning that addresses the question", "A long list of separate points", "A balanced judgement at the end"]}'::jsonb, '{"answer": 1, "explain": "Analyse = chains of developed links, no evaluation needed. Lists of single effects sit at Level 2."}'::jsonb),
('economics:3-1-economic-growth:tips:36e51108', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate: match every point, and answer the exact question", "reading": "<p>The evaluation marks are the ones most often thrown away on this paper.</p>\n<ul>\n<li><strong>Match your points.</strong> Each evaluative comment must strengthen, mitigate or contrast with the point it follows — not raise an unrelated issue. Exemplar 3 lost marks doing exactly that.</li>\n<li><strong>Cover what the question names.</strong> \"Costs AND benefits of fiscal policy\" needs BOTH for Level 3. \"Benefits of globalisation for WORKERS\" means workers — not producers or government, which scored nothing.</li>\n<li><strong>Address ''extent''.</strong> Where the question says \"the extent to which\", weigh HOW MUCH — e.g. it depends on timescale, on how income is distributed, on whether the government passes the benefits on.</li>\n<li><strong>Judge, don''t summarise.</strong> Signal it (\"Overall…\") and support it. A conclusion that merely restates earlier points adds nothing.</li>\n</ul>", "question": "A question asks you to evaluate the benefits of globalisation for WORKERS in Tanzania. Writing about gains to the government...", "options": ["Is fine, as it''s still about Tanzania", "Earns the evaluation marks", "Is required for Level 3", "Scores nothing — it''s the wrong stakeholder"]}'::jsonb, '{"answer": 3, "explain": "The examiners reported that answers about other stakeholders, or about problems rather than benefits, did not address the question and were not credited."}'::jsonb),
('economics:3-1-economic-growth:fib:10b3d249', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'fib', 'fib', 2, '{"question": "Economic growth is the growth over time of ___B1___, usually measured as the annual percentage change in ___B2___ GDP.", "blankOptions": {"B1": ["revenue", "capital", "negative", "GDP"], "B2": ["revenue", "growing", "nominal", "real"]}}'::jsonb, '{"blanks": {"B1": "GDP", "B2": "real"}}'::jsonb),
