('economics:3-1-economic-growth:match:2cff1660', 'economics', 'economics:3-1-economic-growth', '3.1 Economic Growth', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economic growth”?", "options": ["GDP divided by the population — the output of the average person", "The growth over time of GDP — an increase in the value of output", "GDP expressed in money terms, before adjusting for inflation", "GDP adjusted for inflation, so it shows actual output not just higher prices"]}'::jsonb, '{"answer": 1, "explain": "“Economic growth” means: The growth over time of GDP — an increase in the value of output"}'::jsonb),
